```class Solution {
public:
    int strongPasswordChecker(string password) {
        int missingType = 3;
        int a = 1, A = 1, d = 1;
        int repeat = 0, cnt[3] = {0, 0, 0};
        for (int i = 0; i < password.size(); ++i) {
            if (islower(password[i])) a = 0;
            if (isupper(password[i])) A = 0;
            if (isdigit(password[i])) d = 0;
            if (i > 1 && password[i] == password[i-1] && password[i] == password[i-2]) {
                ++repeat;
                ++cnt[repeat % 3];
            } else {
                repeat = 0;
            }
        }
        missingType -= (a | A | d) ^ 1;
        int res = max(0, missingType) + max(0, 6 - (int)password.size());
        if (password.size() < 6) res += cnt[0];
        else if (password.size() <= 20) res += max(cnt[0], cnt[1]);
        else res += cnt[0] + cnt[1] + cnt[2];
        return res;
    }
};
